assert summarize_downtime(events, 3) == [(1, 0, 11), (2, 1, 3), (2, 10, 12)]
try:
    summarize_downtime([{'service': 1, 'start': 5, 'end': 4}], 1)
except ValueError as exc:
    assert str(exc) == 'event end before start'
else:
    raise AssertionError('expected invalid event error')

assert reconcile_inventory({'alpha': 5, 'beta': 2}, [('gamma', 3), ('alpha', -2), ('beta', 5), ('gamma', -1)]) == {'alpha': 3, 'beta': 7, 'gamma': 2}
try:
    reconcile_inventory({'alpha': 1}, [('alpha', -2)])
except ValueError as exc:
    assert str(exc) == 'negative inventory for alpha'
else:
    raise AssertionError('expected negative inventory error')

assert count_active_users([{'user': 1, 'start': 0, 'end': 3}, {'user': 2, 'start': 2, 'end': 5}, {'user': 1, 'start': 4, 'end': 6}, {'user': 3, 'start': 5, 'end': 8}], [2, 4, 6]) == {2: 2, 4: 2, 6: 1}
try:
    count_active_users([{'user': 1, 'start': 3, 'end': 3}], [3])
except ValueError as exc:
    assert str(exc) == 'session end must be after start'
else:
    raise AssertionError('expected invalid session error')

